SELECT HOMEPAGE_ID, GROUP_IDX, CATEGORY_IDX, CATEGORY_NAME, PRINT_SEQ, USE_YN, (SELECT GROUP_NAME FROM TRAINING_CATEGORY_GROUP WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX) AS GROUP_NAME, req_limit_yn, req_limit_type, req_limit_count FROM TRAINING_CATEGORY a WHERE HOMEPAGE_ID = #{homepage_id} AND large_category_idx = #{large_category_idx} AND delete_yn = 'N'
AND GROUP_IDX = #{group_idx}
ORDER BY PRINT_SEQ DESC, add_date desc

${pagingTop} SELECT homepage_id, group_idx, category_idx, category_name, print_seq, use_yn, (SELECT group_name FROM TRAINING_CATEGORY_GROUP WHERE homepage_id = a.homepage_id AND group_idx = a.group_idx) AS group_name, (SELECT code_name FROM TRAINING_CODE2 WHERE training_code = a.large_category_idx) AS large_category_name, req_limit_yn, req_limit_type, req_limit_count, large_category_idx FROM TRAINING_CATEGORY a WHERE homepage_id = #{homepage_id} AND large_category_idx = #{large_category_idx} AND group_idx = #{group_idx} AND delete_yn = 'N'
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY print_seq DESC, add_date desc ${pagingBottom}

SELECT
	homepage_id, group_idx, category_idx, category_name, print_seq, use_yn,
	(SELECT group_name FROM TRAINING_CATEGORY_GROUP WHERE homepage_id = a.homepage_id AND group_idx = a.group_idx) AS group_name,
	(SELECT code_name FROM TRAINING_CODE2 WHERE training_code = a.large_category_idx) AS large_category_name,
	req_limit_yn, req_limit_type, req_limit_count, large_category_idx
FROM
	TRAINING_CATEGORY a
WHERE 
	homepage_id = #{homepage_id}
AND large_category_idx = #{large_category_idx} 
AND group_idx = #{group_idx} 
AND category_idx = #{category_idx} 
AND delete_yn = 'N'

