FROM
	TRAINING_CATEGORY
WHERE 
	homepage_id = #{homepage_id}
AND large_category_idx = #{large_category_idx} 
AND group_idx = #{group_idx} 
AND category_idx = #{category_idx} 
AND delete_yn = 'N'

SELECT COUNT(*)
FROM
	TRAINING
WHERE 
	homepage_id = #{homepage_id}
AND large_category_idx = #{large_category_idx} 
AND group_idx = #{group_idx} 
AND category_idx = #{category_idx} 
AND delete_yn = 'N'

SELECT
	NVL(SUM(req_limit_count), 0) as req_limit_count, COUNT(*) as cnt
FROM
	TRAINING_CATEGORY
WHERE
	homepage_id = #{homepage_id}
AND	group_idx = #{group_idx}
AND	req_limit_yn = 'Y'
AND	category_idx != #{category_idx}
